{
  "items": [
    {
      "title": "German Longitudinal Election Study (GLES)",
      "summary": "Comprehensive multi-component study of voter behavior and political attitudes in German federal elections, including cross-sections, panels, and rolling cross-sections.",
      "topics": [
        "Political behaviour and attitudes",
        "Government, political systems and organisations",
        "Elections"
      ],
      "host": "GESIS"
    },
    {
      "title": "Politbarometer (Germany) – Time Series",
      "summary": "Monthly public opinion surveys by Forschungsgruppe Wahlen archived at GESIS, covering party preferences, evaluations of government, and a wide range of political attitudes.",
      "topics": [
        "Political behaviour and attitudes",
        "Government, political systems and organisations",
        "Elections"
      ],
      "host": "GESIS"
    },
    {
      "title": "Eurobarometer – Standard and Special Series",
      "summary": "EU-wide public opinion surveys archived by GESIS (ZA series) on political trust, participation, governance, and European Parliament elections.",
      "topics": [
        "Political behaviour and attitudes",
        "Government, political systems and organisations",
        "Elections"
      ],
      "host": "GESIS"
    },
    {
      "title": "European Social Survey (ESS)",
      "summary": "Biennial cross-national survey archived by GESIS, featuring modules on political participation, trust in institutions, and policy attitudes.",
      "topics": [
        "Political behaviour and attitudes",
        "Government, political systems and organisations",
        "Elections"
      ],
      "host": "GESIS"
    },
    {
      "title": "ALLBUS – German General Social Survey",
      "summary": "Repeated cross-sectional surveys of the German population archived at GESIS, including extensive measures of political attitudes, party identification, and trust.",
      "topics": [
        "Political behaviour and attitudes",
        "Government, political systems and organisations",
        "Elections"
      ],
      "host": "GESIS"
    },
    {
      "title": "International Social Survey Programme (ISSP) – Role of Government and Citizenship Modules",
      "summary": "Cross-national modules archived by GESIS on government responsibilities, civic engagement, political efficacy, and related attitudes.",
      "topics": [
        "Political behaviour and attitudes",
        "Government, political systems and organisations",
        "Elections"
      ],
      "host": "GESIS"
    },
    {
      "title": "Manifesto Project (MRG/CMP/MARPOR) – Manifesto Data",
      "summary": "Party manifesto content data hosted by GESIS, enabling analysis of party positions, electoral competition, and programmatic change.",
      "topics": [
        "Political behaviour and attitudes",
        "Government, political systems and organisations",
        "Elections"
      ],
      "host": "GESIS"
    },
    {
      "title": "European Values Study (EVS) – Integrated Dataset",
      "summary": "Multi-wave cross-national survey archived by GESIS with measures of political values, trust in institutions, civic participation, and social attitudes.",
